'use client'

import { useState, useEffect, useMemo } from 'react'
import { useRouter } from 'next/navigation'
import { DropResult } from '@hello-pangea/dnd'
import { createClient } from '@/lib/supabaseClient'
import { getLeadsByCloser, updateLeadStatusCloser, devolverNoShowSdr, Lead, Profile, getAllClosers } from '@/lib/leads'
import { useAuth } from '@/contexts/AuthContext'
import { DraggableKanbanBoard, DraggableKanbanColumn } from '@/components/DraggableKanban'
import Sidebar from '@/components/Sidebar'
import CloserActionModal from '@/components/CloserActionModal'
import PremiumSelect from '@/components/ui/PremiumSelect'
import CreateCloserLeadModal from '@/components/CreateCloserLeadModal'

type CloserKanbanStatus = 'REUNIAO_MARCADA' | 'NO_SHOW' | 'ACOMPANHAMENTO' | 'FECHAMENTO' | 'GANHOU' | 'PERDEU'

export default function CloserKanbanPage() {
  const router = useRouter()
  const { user, profile, loading: authLoading } = useAuth()
  
  const [leads, setLeads] = useState<Lead[]>([])
  const [loadingLeads, setLoadingLeads] = useState(true)
  const [error, setError] = useState<string | null>(null)
  
  // Modais de A├º├úo (Arrasto)
  const [actionLead, setActionLead] = useState<Lead | null>(null)
  const [actionType, setActionType] = useState<'GANHOU' | 'PERDEU' | 'NO_SHOW' | null>(null)
  
  // Modal de Cria├º├úo de Lead
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false)

  // Filtros Admin
  const [closers, setClosers] = useState<Profile[]>([])
  const [selectedCloserId, setSelectedCloserId] = useState<string>('')

  // Efeito isolado para o Admin puxar a lista de Closers
  useEffect(() => {
    if (profile?.role === 'admin' || profile?.role === 'marketing') {
      getAllClosers().then(data => {
        setClosers(data)
        if (data.length > 0 && !selectedCloserId) {
          setSelectedCloserId(data[0].id)
        }
      })
    }
  }, [profile])

  useEffect(() => {
    if (authLoading) return
    if (!user || !profile) {
      if (!authLoading && !user) router.replace('/login')
      return
    }
    
    // Admin ou Closer
    if (profile.role !== 'closer' && profile.role !== 'admin' && profile.role !== 'marketing') {
      router.replace('/sdr/kanban')
      return
    }

    loadLeads()
  }, [user, profile, authLoading, router, selectedCloserId])

  const loadLeads = async () => {
    if (!profile) return
    const closerToFetch = (profile.role === 'admin' || profile.role === 'marketing') ? selectedCloserId : profile.id
    if (!closerToFetch) return // aguarda popular selectedCloserId em caso de Admin

    setLoadingLeads(true)
    try {
      const data = await getLeadsByCloser(closerToFetch)
      setLeads(data)
    } catch (err: any) {
      setError(err.message)
    } finally {
      setLoadingLeads(false)
    }
  }

  const reunioesMarcadas = leads.filter(l => l.status_closer === 'REUNIAO_MARCADA').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
  const noShows = leads.filter(l => l.status_closer === 'NO_SHOW').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
  const acompanhamento = leads.filter(l => l.status_closer === 'ACOMPANHAMENTO').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
  const fechamento = leads.filter(l => l.status_closer === 'FECHAMENTO').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
  const ganhou = leads.filter(l => l.status_closer === 'GANHOU').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
  const perdeu = leads.filter(l => l.status_closer === 'PERDEU').sort((a,b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())

  const handleDragEnd = async (result: DropResult) => {
    const { destination, source, draggableId } = result
    if (!destination || (destination.droppableId === source.droppableId && destination.index === source.index)) {
      return
    }

    const leadId = parseInt(draggableId)
    const newStatus = destination.droppableId as CloserKanbanStatus
    const lead = leads.find(l => l.id === leadId)
    if (!lead) return

    // Intercepta├º├Áes de Status Especiais (Salva otimista temporariamente e abre modal)
    if (newStatus === 'GANHOU' || newStatus === 'PERDEU' || newStatus === 'NO_SHOW') {
      setLeads(prev => prev.map(l => l.id === leadId ? { ...l, status_closer: newStatus } : l))
      setActionLead(lead)
      setActionType(newStatus)
      return // Espera o modal
    }

    // Status Comuns - Salva otimista
    setLeads(prev => prev.map(l => l.id === leadId ? { ...l, status_closer: newStatus } : l))
    try {
      await updateLeadStatusCloser(leadId, newStatus)
    } catch {
      loadLeads() // Rollback on error
    }
  }

  const handleModalConfirm = async (data: { valor?: number; motivo?: string }) => {
    if (!actionLead || !actionType) return
    const leadId = actionLead.id

    // Fechar modal otimista
    const finalType = actionType
    setActionLead(null)
    try {
      if (finalType === 'NO_SHOW') {
        const resp = await devolverNoShowSdr(leadId)
        if (!resp.success) {
           setError(resp.error || 'Erro ao devolver lead')
           loadLeads() // rollback
        }
      } else {
        // GANHOU ou PERDEU
        setLeads(prev => prev.map(l => l.id === leadId ? { 
          ...l, 
          valor_venda: data.valor || l.valor_venda,
          motivo_perda: data.motivo || l.motivo_perda
        } : l))

        // Save status
        await updateLeadStatusCloser(leadId, finalType)
        
        // Save extra data manually
        const supabase = createClient()
        if (finalType === 'GANHOU' && data.valor) {
          await supabase.from('leads').update({ valor_venda: data.valor }).eq('id', leadId)
        } else if (finalType === 'PERDEU' && data.motivo) {
          await supabase.from('leads').update({ motivo_perda: data.motivo }).eq('id', leadId)
        }
      }
    } catch (err: any) {
      console.error('Erro na a├º├úo do closer', err)
      setError(err.message)
      loadLeads()
    }
  }

  const handleDeleteLead = (leadId: number) => {
    setLeads(prev => prev.filter(l => l.id !== leadId))
  }

  // Cancelamento do Modal tamb├®m precisa fazer rollback otimista
  const handleModalCancel = () => {
    setActionType(null)
    setActionLead(null)
    loadLeads() // Recarrega do banco pra desfazer o state otimista
  }

  if (loadingLeads || authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-slate-800"></div>
      </div>
    )
  }

  if (!profile) return null

  return (
    <Sidebar>
      <div className="h-screen flex flex-col bg-gray-50">
        <header className="flex-shrink-0 bg-white border-b border-gray-200 px-6 py-4 z-20 relative">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              <h1 className="text-2xl font-bold text-gray-900">Painel Closer</h1>
              {(profile.role === 'admin' || profile.role === 'marketing') && closers.length > 0 && (
                <div className="w-64 max-w-sm ml-4 z-50">
                  <PremiumSelect
                    value={selectedCloserId}
                    onChange={setSelectedCloserId}
                    options={closers.map(c => ({ value: c.id, label: c.name }))}
                    placeholder="Filtrar por Closer..."
                  />
                </div>
              )}
            </div>

            <div className="flex items-center gap-4">
              <button
                onClick={() => setIsCreateModalOpen(true)}
                className="px-4 py-2 bg-[#8B0000] text-white rounded-lg hover:bg-[#6B0000] transition-colors shadow-md text-sm font-semibold flex items-center gap-2 h-fit"
                title="Criar Lead Manualmente"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                Novo Lead
              </button>
              <div className="flex gap-4 p-2 bg-gray-50 rounded-xl">
                <div className="text-center px-4 border-r">
                <p className="text-xl font-bold text-slate-700">{leads.length}</p>
                <p className="text-xs text-gray-500">Meus Leads</p>
              </div>
              <div className="text-center px-4">
                <p className="text-xl font-bold text-emerald-600">{ganhou.length}</p>
                <p className="text-xs text-gray-500">Ganhos</p>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 min-h-0 p-6 overflow-x-auto">
          {error && (
            <div className="mb-4 bg-red-50 text-red-700 p-3 rounded-xl border border-red-200">
              {error}
            </div>
          )}

          <div className="h-full rounded-2xl bg-white/50 border border-gray-200 p-4 min-w-[1200px]">
            <DraggableKanbanBoard onDragEnd={handleDragEnd}>
              <DraggableKanbanColumn
                id="REUNIAO_MARCADA"
                titulo="Reuni├Áes Marcadas"
                leads={reunioesMarcadas}
                cor="#3b82f6"
                isCloserView
                onDeletar={handleDeleteLead}
              />
              <DraggableKanbanColumn
                id="ACOMPANHAMENTO"
                titulo="Acompanhamento"
                leads={acompanhamento}
                cor="#8b5cf6"
                isCloserView
                onDeletar={handleDeleteLead}
              />
              <DraggableKanbanColumn
                id="FECHAMENTO"
                titulo="Fechamento"
                leads={fechamento}
                cor="#14b8a6"
                isCloserView
                onDeletar={handleDeleteLead}
              />
              <DraggableKanbanColumn
                id="GANHOU"
                titulo="Ganhou"
                leads={ganhou}
                cor="#059669"
                isCloserView
                onDeletar={handleDeleteLead}
              />
              <DraggableKanbanColumn
                id="PERDEU"
                titulo="Perdeu"
                leads={perdeu}
                cor="#ef4444"
                isCloserView
                onDeletar={handleDeleteLead}
              />
              <DraggableKanbanColumn
                id="NO_SHOW"
                titulo="No-Show (Devolver)"
                leads={noShows}
                cor="#dc2626"
                isCloserView
                onDeletar={handleDeleteLead}
              />
            </DraggableKanbanBoard>
          </div>
        </main>

        <CloserActionModal
          isOpen={!!actionType}
          type={actionType}
          leadName={actionLead?.nome}
          onClose={handleModalCancel}
          onConfirm={handleModalConfirm}
        />

        <CreateCloserLeadModal
          isOpen={isCreateModalOpen}
          onClose={() => setIsCreateModalOpen(false)}
          closerId={(profile.role === 'admin' || profile.role === 'marketing') ? selectedCloserId : profile.id}
          onSuccess={(newLead) => {
            setLeads(prev => [newLead, ...prev])
          }}
        />
      </div>
    </Sidebar>
  )
}

'use client'

import { useState } from 'react'
import { checkLeadExists, createLead, Lead } from '@/lib/leads'
import PremiumSelect from './ui/PremiumSelect'

interface CreateCloserLeadModalProps {
  isOpen: boolean
  onClose: () => void
  onSuccess: (lead: Lead) => void
  closerId: string | null
}

export default function CreateCloserLeadModal({ isOpen, onClose, onSuccess, closerId }: CreateCloserLeadModalProps) {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [duplicateLead, setDuplicateLead] = useState<Lead | null>(null)

  const [formData, setFormData] = useState({
    nome: '',
    whatsapp: '',
    tipo_hospedagem: '',
    faturamento_medio: '',
    status_closer: 'ACOMPANHAMENTO' as const
  })

  // Mandatory fields for basic closer lead
  const isFormValid = formData.nome && formData.whatsapp && formData.tipo_hospedagem

  const TIPOS_HOSPEDAGEM = [
    { value: 'Hotel, Pousada ou Resort', label: 'Hotel, Pousada ou Resort' },
    { value: 'Cabanas e Chal├®s', label: 'Cabanas e Chal├®s' },
    { value: 'Outros', label: 'Outros' },
  ]

  const FATURAMENTOS = [
    { value: 'Menos de R$ 5 mil', label: 'Menos de R$ 5 mil' },
    { value: 'Entre R$ 5 a R$ 20 mil', label: 'Entre R$ 5 a R$ 20 mil' },
    { value: 'Entre R$ 20 a R$ 50 mil', label: 'Entre R$ 20 a R$ 50 mil' },
    { value: 'Entre R$ 50 a R$ 100 mil', label: 'Entre R$ 50 a R$ 100 mil' },
    { value: 'Entre R$ 100 a R$ 500 mil', label: 'Entre R$ 100 a R$ 500 mil' },
    { value: 'Mais de R$ 500 mil', label: 'Mais de R$ 500 mil' },
  ]

  const STATUS_CLOSER_OPCOES = [
    { value: 'REUNIAO_MARCADA', label: '1. Reuni├úo Marcada' },
    { value: 'ACOMPANHAMENTO', label: '2. Acompanhamento' },
    { value: 'FECHAMENTO', label: '3. Fechamento' },
    { value: 'GANHOU', label: 'Ganhou (Cliente)' },
    { value: 'PERDEU', label: 'Perdeu (Lost)' },
    { value: 'NO_SHOW', label: 'No Show' },
  ]

  if (!isOpen) return null

  const handleCheckDuplicity = async () => {
    if (!isFormValid) return

    setLoading(true)
    setError(null)
    setDuplicateLead(null)
    try {
      const existing = await checkLeadExists(formData.whatsapp)
      if (existing) {
        setDuplicateLead(existing)
      } else {
        await handleSave()
      }
    } catch (err) {
      setError('Erro ao verificar duplicidade')
    } finally {
      if (duplicateLead) {
        setLoading(false) // Only un-load if stopped. If continuing to handleSave, it manages its own loading.
      }
    }
  }

  const handleSave = async () => {
    try {
      const newLead = await createLead({
        nome: formData.nome,
        whatsapp: formData.whatsapp,
        whatsapp_formatado: formData.whatsapp.replace(/\D/g, ''),
        tipo_hospedagem: formData.tipo_hospedagem,
        faturamento_medio: formData.faturamento_medio || null,
        owner_closer_id: closerId,
        status_closer: formData.status_closer as any,
        owner_sdr_id: null,
        status_sdr: null,
      })
      onSuccess(newLead)
      handleClose()
    } catch (err) {
      setError('Erro ao criar lead. Verifique sua conex├úo ou contate o suporte.')
      setLoading(false)
    }
  }

  const handleClose = () => {
    setFormData({
      nome: '',
      whatsapp: '',
      tipo_hospedagem: '',
      faturamento_medio: '',
      status_closer: 'ACOMPANHAMENTO'
    })
    setDuplicateLead(null)
    setError(null)
    onClose()
  }

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <h2 className="text-xl font-bold text-gray-900">Novo Lead (Closer)</h2>
          <button onClick={handleClose} className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-xl transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 space-y-4">
          {error && (
            <div className="p-3 bg-red-50 border border-red-200 text-red-700 text-sm rounded-xl">
              {error}
            </div>
          )}

          {duplicateLead ? (
            <div className="p-4 bg-red-50 border border-red-200 rounded-xl">
              <div className="flex gap-3">
                <svg className="w-6 h-6 text-red-600 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
                <div>
                  <h3 className="font-bold text-red-900">Lead j├í existe!</h3>
                  <p className="text-sm text-red-800 mt-1">
                    Este WhatsApp j├í pertence ao lead <strong>{duplicateLead.nome}</strong> no CRM.
                    <br/><br/>
                    <em>A├º├úo Bloqueada: N├úo ├® poss├¡vel recadastrar este lead silenciosamente no painel do Closer para evitar conflito de triplicidade. Entre em contato com o Gestor para reatribui├º├úo, se for o caso.</em>
                  </p>
                  <div className="mt-4 flex gap-2">
                    <button
                      onClick={() => setDuplicateLead(null)}
                      className="px-3 py-1.5 text-xs font-semibold text-red-900 bg-red-100 hover:bg-red-200 rounded-lg transition-colors"
                    >
                      Corrigir N├║mero
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Nome Completo *</label>
                <input
                  type="text"
                  value={formData.nome}
                  onChange={e => setFormData({ ...formData, nome: e.target.value })}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#8B0000] focus:border-transparent transition-all outline-none"
                  placeholder="Nome do lead"
                  required
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">WhatsApp *</label>
                <input
                  type="text"
                  value={formData.whatsapp}
                  onChange={e => setFormData({ ...formData, whatsapp: e.target.value })}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#8B0000] focus:border-transparent transition-all outline-none"
                  placeholder="+55 (11) 99999-9999"
                  required
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <PremiumSelect
                  label="Hospedagem *"
                  options={TIPOS_HOSPEDAGEM}
                  value={formData.tipo_hospedagem}
                  onChange={val => setFormData({ ...formData, tipo_hospedagem: val })}
                  placeholder="Selecione..."
                />
                <PremiumSelect
                  label="Faturamento"
                  options={FATURAMENTOS}
                  value={formData.faturamento_medio}
                  onChange={val => setFormData({ ...formData, faturamento_medio: val })}
                  placeholder="Opcional"
                />
              </div>

              <div className="mt-2 pt-2 border-t border-gray-100">
                <PremiumSelect
                  label="Status do Funil Inicial *"
                  options={STATUS_CLOSER_OPCOES}
                  value={formData.status_closer}
                  onChange={val => setFormData({ ...formData, status_closer: val as any })}
                  placeholder="Selecione a coluna"
                />
              </div>
            </>
          )}
        </div>

        <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex gap-3">
          <button
            onClick={handleClose}
            className="flex-1 px-4 py-2.5 text-gray-700 font-semibold hover:bg-gray-200 rounded-xl transition-colors"
          >
            Cancelar
          </button>
          {!duplicateLead && (
            <button
              onClick={handleCheckDuplicity}
              disabled={loading || !isFormValid}
              className={`flex-1 px-4 py-2.5 text-white font-semibold rounded-xl transition-all ${
                loading || !isFormValid
                  ? 'bg-gray-400 cursor-not-allowed' 
                  : 'bg-[#8B0000] hover:bg-[#6B0000] shadow-lg shadow-red-200'
              }`}
            >
              {loading ? 'Processando...' : 'Criar Lead'}
            </button>
          )}
        </div>
      </div>
    </div>
  )
}
